<script setup lang="ts">
import { ref } from 'vue';import { showFailToast,showSuccessToast,showConfirmDialog } from 'vant';import { useRouter } from 'vue-router';import PageHeader from '../components/PageHeader.vue';import { useAuthStore } from '../stores/auth';const auth=useAuthStore();const router=useRouter();const show=ref(false);const password=ref('');const saving=ref(false);async function change(){if(password.value.length<8)return showFailToast('新密码至少 8 位');saving.value=true;try{await auth.changePassword(password.value);show.value=false;password.value='';showSuccessToast('密码已修改')}catch(e){showFailToast(e instanceof Error?e.message:'修改失败')}finally{saving.value=false}}async function logout(){await showConfirmDialog({title:'退出登录',message:'确定要退出当前账号吗？'});await auth.logout();router.replace('/login')}
</script>
<template><section class="page"><PageHeader eyebrow="MY PROFILE" title="个人中心"/><div class="card hero"><div class="row"><div><div class="muted">我的昵称</div><h2>{{auth.profile?.nickname}}</h2></div><span class="tag">{{auth.isAdmin?'管理员':'普通用户'}}</span></div></div><van-cell-group inset><van-cell title="账号" :value="auth.profile?.username"/><van-cell title="初始体重" :value="`${auth.profile?.initial_weight||0} kg`"/><van-cell title="目标体重" :value="`${auth.profile?.target_weight||0} kg`"/><van-cell title="体重趋势" is-link to="/trend"/><van-cell v-if="auth.isAdmin" title="管理后台" is-link to="/admin"/><van-cell title="修改密码" is-link @click="show=true"/></van-cell-group><div style="margin-top:18px"><button class="secondary-btn" @click="logout">退出登录</button></div><van-dialog v-model:show="show" title="修改密码" show-cancel-button :before-close="async(action)=>{if(action==='confirm')await change();return action==='cancel'}"><van-field v-model="password" type="password" placeholder="至少 8 位新密码"/></van-dialog></section></template>
